<script setup>
const secondsAngle = ref(0)
const minutesAngle = ref(0)
const hoursAngle = ref(0)

let rafId

function update() {
	const now = new Date()
	const s = now.getSeconds() + now.getMilliseconds() / 1000
	const m = now.getMinutes() + s / 60
	const h = (now.getHours() % 12) + m / 60

	secondsAngle.value = s * 6
	minutesAngle.value = m * 6
	hoursAngle.value = h * 30

	rafId = requestAnimationFrame(update)
}

onMounted(() => {
	update()
})

onUnmounted(() => {
	cancelAnimationFrame(rafId)
})
</script>

<style>
/* Base */
.fill-face {
  fill: #373636
}

.fill-dark {
  fill: #323232
}

.fill-light {
  fill: #fff
}

.fill-center {
  fill: #363636
}

/* Hand colors */
.fill-hour {
  fill: oklch(0.55 0.24 360)
}

.fill-minute {
  fill: oklch(0.65 0.14 195)
}

.fill-second {
  fill: oklch(0.65 0.15 350)
}

/* Specular highlight colors */
.fill-spec-dark {
  fill: oklch(0.5 0 0)
}

.fill-spec-hour {
  fill: oklch(0.7 0.2 360)
}

.fill-spec-minute {
  fill: oklch(0.8 0.14 195)
}

.fill-spec-second {
  fill: oklch(0.75 0.14 350)
}
</style>
